// 读取测试排版规则说明文档内容并解析为排版配置
var specDoc = WPS.Documents.Open("/Users/cassia/Desktop/dyx/wpsjs/3. 中水设计文档校排/测试排版规则说明.docx");
var content = "";
for (var i = 1; i <= specDoc.Paragraphs.Count; i++) {
    content += specDoc.Paragraphs(i).Range.Text + "\n";
}
specDoc.Close(false);

// 使用 LLM 解析规范文档（这里直接返回示例配置，实际应由 LLM 生成）
return {
    version: "1.0",
    fontDefaults: { fontCN: "宋体", fontEN: "Times New Roman" },
    numberingPatterns: {
        zhangTitle: ["^第 [一二三四五六七八九十]+章", "^\\d{1,2}\\s+[\\u4e00-\\u9fff]"],
        heading2: ["^\\d+\\.\\d+(\\s|$)"],
        heading3: ["^\\d+\\.\\d+\\.\\d+(\\s|$)"],
        tableCaption: ["^表\\s*[\\d\\.A-Za-z\\-]+"],
        figureCaption: ["^图\\s*[\\d\\.A-Za-z\\-]+"]
    },
    paragraphRules: {
        zhangTitle: { fontCN: "黑体", fontSize: 16, bold: true, alignment: 1, spaceBefore: 12, spaceAfter: 6, firstLineIndent: 0 },
        heading2: { fontCN: "黑体", fontSize: 14, bold: true, alignment: 0, spaceBefore: 6, spaceAfter: 6, firstLineIndent: 0 },
        heading3: { fontCN: "楷体", fontSize: 12, bold: false, alignment: 0, spaceBefore: 6, spaceAfter: 6, firstLineIndent: 0 },
        body: { fontCN: "宋体", fontSize: 12, alignment: 3, firstLineIndent: 24, lineSpacing: 20, lineSpacingRule: 4 },
        tableCaption: { fontCN: "楷体", fontSize: 10.5, alignment: 1, spaceBefore: 6, spaceAfter: 6, firstLineIndent: 0 },
        figureCaption: { fontCN: "楷体", fontSize: 10.5, alignment: 1, spaceBefore: 6, spaceAfter: 6, firstLineIndent: 0 }
    },
    documentInfo: { pageMargins: { top: 56.7, bottom: 56.7, left: 70.9, right: 70.9 } }
};

// 从已打开的文档中获取测试排版规则说明的内容
var specDoc = null;
for (var i = 1; i <= WPS.Documents.Count; i++) {
    if (WPS.Documents(i).Name === "测试排版规则说明.docx") {
        specDoc = WPS.Documents(i);
        break;
    }
}
if (!specDoc) {
    return { error: "未找到测试排版规则说明文档" };
}

var content = "";
for (var j = 1; j <= specDoc.Paragraphs.Count; j++) {
    content += specDoc.Paragraphs(j).Range.Text + "\n";
}
return { success: true, content: content.substring(0, 5000) };
